SELECT button_text
FROM buttons
WHERE state_id = 1;

SELECT AVG(interaction_count) AS average_interactions
FROM (
  SELECT button_id, COUNT(*) AS interaction_count
  FROM button_interactions
  GROUP BY button_id
);

SELECT interaction_type, device_type, COUNT(*) as interaction_count
FROM button_interactions
GROUP BY interaction_type, device_type;

SELECT COUNT(*) 
FROM buttons 
WHERE style_id = 1;

SELECT button_text, url
FROM buttons
WHERE button_id = 1;

SELECT created_by, COUNT(updated_by) AS total_updates
FROM buttons
GROUP BY created_by;

SELECT COUNT(*) 
FROM buttons 
WHERE style_id = (SELECT style_id FROM button_styles WHERE style_name = 'Primary');
